    public function getSourceContext(): Source
    {
        return new Source("<h2 class=\"mb-4\">Changer le mot de passe</h2>

{# Messages flash #}
{% for message in app.flashes('error') %}
    <div class=\"alert alert-danger\">
        {{ message }}
    </div>
{% endfor %}

{% for message in app.flashes('success') %}
    <div class=\"alert alert-success\">
        {{ message }}
    </div>
{% endfor %}

<div class=\"card\">
    <div class=\"card-body\">

        {{ form_start(form) }}

        <div class=\"mb-3\">
            {{ form_label(form.currentPassword) }}
            {{ form_widget(form.currentPassword, {'attr': {'class': 'form-control'}}) }}
            {{ form_errors(form.currentPassword) }}
        </div>

        <div class=\"mb-3\">
            {{ form_label(form.newPassword) }}
            {{ form_widget(form.newPassword, {'attr': {'class': 'form-control'}}) }}
            {{ form_errors(form.newPassword) }}
        </div>

        <button type=\"submit\" class=\"btn btn-primary\">
            Mettre à jour
        </button>

        {{ form_end(form) }}

    </div>
</div>", "profile/change_password.html.twig", "/home/yassine/Bureau/product/templates/profile/change_password.html.twig");
